import React, { useState } from "react";
import { Box, Typography, Button, TextField, Alert } from "@mui/material";
import { useNavigate } from "react-router-dom";
import { uploadRiderDocs } from "../services/api";

export default function DocumentUpload() {
  const [license, setLicense] = useState("");
  const [rc, setRc] = useState("");
  const [insurance, setInsurance] = useState("");
  const [photo, setPhoto] = useState("");
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const navigate = useNavigate();

  const handleUpload = async () => {
    const token = localStorage.getItem("token");
    if (!token) {
      navigate("/login");
      return;
    }

    try {
      const res = await uploadRiderDocs(token, { license, rc, insurance, photo });
      if (res.data.success) {
        setSuccess("Documents uploaded successfully! Awaiting admin approval.");
        setError("");
        setTimeout(() => navigate("/rider-dashboard"), 1500);
      } else {
        setError(res.data.message || "Failed to upload documents");
      }
    } catch (err) {
      console.error("Upload error:", err);
      setError("Server error. Try again.");
    }
  };

  return (
    <Box sx={{ p: 4, maxWidth: 500, mx: "auto" }}>
      <Typography variant="h4" sx={{ fontWeight: "bold", mb: 3 }}>
        Upload Documents
      </Typography>

      {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
      {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

      <TextField
        label="License Number"
        fullWidth
        margin="normal"
        value={license}
        onChange={(e) => setLicense(e.target.value)}
      />
      <TextField
        label="RC Number"
        fullWidth
        margin="normal"
        value={rc}
        onChange={(e) => setRc(e.target.value)}
      />
      <TextField
        label="Insurance Policy Number"
        fullWidth
        margin="normal"
        value={insurance}
        onChange={(e) => setInsurance(e.target.value)}
      />
      <TextField
        label="Profile Photo URL"
        fullWidth
        margin="normal"
        value={photo}
        onChange={(e) => setPhoto(e.target.value)}
      />

      <Button
        variant="contained"
        sx={{ mt: 3, bgcolor: "black", color: "white" }}
        onClick={handleUpload}
      >
        Submit Documents
      </Button>
    </Box>
  );
}
